    ('cat_books_with_pauses', 1, 1, 'visible', true, false, 'Best for classic flap pause', 'Dear Zoo', 'Rod Campbell', 'Penguin UK', 'https://www.penguin.co.uk/books/11124/dear-zoo-by-campbell-rod/9780230749672', NULL, '£7.99', 'in_stock', 'Suitable for 1–2 years', 'A sturdy lift the flap board book where each crate opens to a different animal, with a simple repeating line that invites a pause before the reveal.', 'At this age the joy is waiting with you before the flap opens, not racing through pages. Dear Zoo keeps the reveal short enough for a restless lap, and the repetition lets them join the “so we sent him back” bit once they know it.', 'At this age the joy is waiting with you before the flap opens, not racing through pages. Dear Zoo keeps the reveal short enough for a restless lap, and the repetition lets them join the “so we sent him back” bit once they know it.', NULL, 'buy', true, NULL, NULL, NULL, 'strong', ARRAY['https://www.penguin.co.uk/books/11124/dear-zoo-by-campbell-rod/9780230749672']::text[], 'none'),
    ('cat_books_with_pauses', 2, 2, 'visible', true, true, 'Best for hide and seek flaps', 'Where''s Spot?', 'Eric Hill', 'Penguin UK', 'https://www.penguin.co.uk/books/122792/wheres-spot-by-hill-eric/9780723263661', NULL, '£7.99', 'in_stock', 'Toddler lift the flap classic', 'The original Spot lift the flap board book, with sturdy flaps hiding animals and Spot himself, made for pointing, guessing and one more peek.', 'After Dear Zoo, a second flap book is useful when the game is “who is under here?” with a puppy they already recognise. The pauses stay short and the flaps are tough enough for determined little fingers on a busy afternoon. This pick is strongest for hide and seek flaps.', 'After Dear Zoo, a second flap book is useful when the game is “who is under here?” with a puppy they already recognise. The pauses stay short and the flaps are tough enough for determined little fingers on a busy afternoon. This pick is strongest for hide and seek flaps.', NULL, 'buy', true, NULL, NULL, NULL, 'strong', ARRAY['https://www.penguin.co.uk/books/122792/wheres-spot-by-hill-eric/9780723263661']::text[], 'none'),
    ('cat_books_with_pauses', 3, 3, 'visible', true, true, 'Best for farm day flaps', 'Ladybird Lift the Flap: Busy Farm', 'Ladybird', 'Penguin UK', 'https://www.penguin.co.uk/books/180564/ladybird-lift-the-flap-book-busy-farm-by-ladybird/9781409308560', NULL, '£6.99', 'in_stock', 'Toddler board book', 'A bright Ladybird board book that follows a farmer through the day, with robust flaps, labelled pictures and a ladybird to spot on every page.', 'Farm words and day order start to stick when they can lift for the next job on the page. This one stays simple enough for a first birthday lap while giving a different scene set from Spot or Dear Zoo on a shared sofa read.', 'Farm words and day order start to stick when they can lift for the next job on the page. This one stays simple enough for a first birthday lap while giving a different scene set from Spot or Dear Zoo on a shared sofa read.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY['https://www.penguin.co.uk/books/180564/ladybird-lift-the-flap-book-busy-farm-by-ladybird/9781409308560']::text[], 'none'),
    ('cat_books_with_pauses', 4, 4, 'visible', true, true, 'Best for caterpillar farm flaps', 'The Very Hungry Caterpillar’s Lift and Learn: Farm', 'Eric Carle', 'Penguin UK', 'https://www.penguin.co.uk/books/456451/the-very-hungry-caterpillars-lift-and-learn-farm-by-carle-eric/9780241648926', NULL, '£7.99', 'in_stock', 'Board book', 'A bold lift the flap farm board book with the Very Hungry Caterpillar, hiding animals behind barn, tractor and hay scenes to explore together.', 'If the caterpillar is already a friend on the shelf, farm flaps extend the pause game without a brand new character to learn. Keep it for daytime looking rather than a sleepy bedtime if they want every flap opened twice.', 'If the caterpillar is already a friend on the shelf, farm flaps extend the pause game without a brand new character to learn. Keep it for daytime looking rather than a sleepy bedtime if they want every flap opened twice.', NULL, 'buy', true, NULL, NULL, NULL, 'good', ARRAY['https://www.penguin.co.uk/books/456451/the-very-hungry-caterpillars-lift-and-learn-farm-by-carle-eric/9780241648926']::text[], 'none'),
    ('cat_books_with_pauses', 5, 5, 'visible', true, true, 'Best for Peppa farm flaps', 'Peppa Pig: Peppa at the Farm', 'Peppa Pig', 'Penguin UK', 'https://www.penguin.co.uk/books/445500/peppa-pig-peppa-at-the-farm-by-pig-peppa/9780241543443', NULL, '£7.99', 'in_stock', 'Preschool board book', 'A Peppa Pig lift the flap board book set on a petting farm, with large flaps to open while hunting for hiding animals with Peppa and George.', 'Character love is real at this age, and Peppa can pull a longer look than a brand new cast. Use it when they already shout for Peppa, and keep one quieter classic for bedtime so flaps do not only mean screen energy.', 'Character love is real at this age, and Peppa can pull a longer look than a brand new cast. Use it when they already shout for Peppa, and keep one quieter classic for bedtime so flaps do not only mean screen energy.', NULL, 'buy', true, NULL, NULL, NULL, 'good', ARRAY['https://www.penguin.co.uk/books/445500/peppa-pig-peppa-at-the-farm-by-pig-peppa/9780241543443']::text[], 'none'),
    ('cat_books_with_pauses', 6, 6, 'visible', true, true, 'Best for Spot walk flaps', 'Spot''s First Walk', 'Eric Hill', 'Penguin UK', 'https://www.penguin.co.uk/books/11125/spots-first-walk-by-hill-eric/9780723263678', NULL, '£7.99', 'in_stock', 'Spot lift the flap', 'A Spot lift the flap board book about a first walk, with sturdy flaps and simple pages for pointing at animals and surprises along the way.', 'This is the second Spot title only, chosen because the walk story matches newly mobile days outdoors and indoors. Cap Spot at two in the shown set so the shelf does not become one puppy forever on every gift list.', 'This is the second Spot title only, chosen because the walk story matches newly mobile days outdoors and indoors. Cap Spot at two in the shown set so the shelf does not become one puppy forever on every gift list.', NULL, 'buy', true, NULL, NULL, NULL, 'good', ARRAY['https://www.penguin.co.uk/books/11125/spots-first-walk-by-hill-eric/9780723263678']::text[], 'none'),
    ('cat_books_with_pauses', 7, 7, 'visible', true, true, 'Best for double flap farm', 'Who is on the Farm, Spot?', 'Puffin', 'Penguin UK', 'https://www.penguin.co.uk/books/462962/who-is-on-the-farm-spot-by-hill-eric/9780241720998', NULL, '£7.99', 'in_stock', 'From early years', 'A Spot farm board book with two flaps on each page, so you lift once for the animal and again for an extra surprise sound or reveal.', 'Listed under Puffin here to keep Eric Hill branding to two shown titles. The double flap slows the page in a useful way when they are ready for a slightly longer shared sit than Dear Zoo on a weekend morning.', 'Listed under Puffin here to keep Eric Hill branding to two shown titles. The double flap slows the page in a useful way when they are ready for a slightly longer shared sit than Dear Zoo on a weekend morning.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY['https://www.penguin.co.uk/books/462962/who-is-on-the-farm-spot-by-hill-eric/9780241720998']::text[], 'none'),
