    ('cat_transition_basket', 3, 3, 'visible', true, true, 'Best for soft goodbye friend', 'Lamaze Freddie the Firefly', 'Lamaze', 'Boots', 'https://www.boots.com/lamaze-freddie-the-firefly-10065234', NULL, '£12.99', 'in_stock', '12 months+', 'A soft clip on firefly to live inside the transition basket so the goodbye object stays familiar across car seats and cafes.', 'The basket is the system; Freddie is the familiar friend inside it. Keep the same soft toy in the basket for a week so transitions stay predictable. One short go with Lamaze Freddie the Firefly is enough before you tidy away.', 'The basket is the system; Freddie is the familiar friend inside it. Keep the same soft toy in the basket for a week so transitions stay predictable. One short go with Lamaze Freddie the Firefly is enough before you tidy away.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY['https://www.boots.com/lamaze-freddie-the-firefly-10065234']::text[], 'none'),
    ('cat_transition_basket', 4, 4, 'visible', true, true, 'Best for quiet goodbye shaker', 'Bigjigs Egg Shaker', 'Bigjigs', 'The Toy Tree', 'https://www.thetoytree.co.uk/product/egg-shaker/', NULL, '£6.00', 'in_stock', '12 months+', 'A small wooden egg shaker to sit in the transition basket when you want one quiet sound object for the ending phrase.', 'One quiet shaker in the basket is enough for the goodbye. Leave louder instruments at home so the ending stays short and clear. Leave the basket where morning clutter gathers so clearing the floor stays obvious for both of you.', 'One quiet shaker in the basket is enough for the goodbye. Leave louder instruments at home so the ending stays short and clear. Leave the basket where morning clutter gathers so clearing the floor stays obvious for both of you.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY['https://www.thetoytree.co.uk/product/egg-shaker/']::text[], 'none'),
    ('cat_transition_basket', 5, 5, 'visible', true, true, 'Best for push goodbye route', 'The Buddy Stroller', 'Lovevery', 'Lovevery UK', 'https://www.lovevery.co.uk/products/the-buddy-stroller', NULL, '£49.00', 'in_stock', '12 months+', 'A toddler push stroller for carrying the transition soft toy on the short walk from door to car when leaving the house.', 'Some children want to push the goodbye object themselves. Load one soft toy only so the stroller stays steady on the path to the door. Put The Buddy Stroller where you both sit most evenings so the invite is easy.', 'Some children want to push the goodbye object themselves. Load one soft toy only so the stroller stays steady on the path to the door. Put The Buddy Stroller where you both sit most evenings so the invite is easy.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY['https://www.lovevery.co.uk/products/the-buddy-stroller']::text[], 'none'),
    ('cat_two_block_towers', 1, 1, 'visible', true, false, 'Best for crane and blocks', 'UPPSTÅ Crane with Blocks', 'IKEA', 'IKEA UK', 'https://www.ikea.com/gb/en/p/uppsta-crane-with-blocks-multicolour-beech-40580851/', NULL, '£10.00', 'in_stock', '12 months+', 'A wooden crane with chunky blocks for short stack and tip play, sized so newly walking toddlers can build two block towers then crash them.', 'After the first birthday, the fun is placing one block on another and watching the crash. This crane set keeps the pieces chunky enough for short towers without a huge heirloom box price. Keep UPPSTÅ Crane with Blocks in easy reach for the next short try.', 'After the first birthday, the fun is placing one block on another and watching the crash. This crane set keeps the pieces chunky enough for short towers without a huge heirloom box price. Keep UPPSTÅ Crane with Blocks in easy reach for the next short try.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY['https://www.ikea.com/gb/en/p/uppsta-crane-with-blocks-multicolour-beech-40580851/']::text[], 'none'),
    ('cat_two_block_towers', 2, 2, 'visible', true, true, 'Best for nesting beakers', 'UPPSTÅ building beakers, multicolour', 'IKEA', 'IKEA UK', 'https://www.ikea.com/gb/en/p/uppsta-building-beakers-multicolour-70513884/', NULL, '£8.00', 'in_stock', '12 months+', 'A set of colourful nesting beakers for stacking, nesting and tip play on the living room floor after the first birthday.', 'Beakers give a softer crash than wood and travel well to grandparents. Keep sessions short so stacking stays the job rather than a whole room tip out. Leave UPPSTÅ building beakers, multicolour out where they can find it again tomorrow.', 'Beakers give a softer crash than wood and travel well to grandparents. Keep sessions short so stacking stays the job rather than a whole room tip out. Leave UPPSTÅ building beakers, multicolour out where they can find it again tomorrow.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY['https://www.ikea.com/gb/en/p/uppsta-building-beakers-multicolour-70513884/']::text[], 'none'),
    ('cat_two_block_towers', 3, 3, 'visible', true, true, 'Best for fabric stack cups', 'Lamaze Pile & Play Cups', 'Lamaze', 'Boots', 'https://www.boots.com/lamaze-pile-play-cups-10203340', NULL, '£10.00', 'in_stock', '12 months+', 'Soft fabric stacking cups for short tower and tip play when hard wood pieces sound loud on a small living room floor.', 'Fabric cups keep the crash soft for tired evenings. Build two short towers together, tip them, and pack them away before they become a whole room tip out. One short go with Lamaze Pile & Play is enough before you tidy away.', 'Fabric cups keep the crash soft for tired evenings. Build two short towers together, tip them, and pack them away before they become a whole room tip out. One short go with Lamaze Pile & Play is enough before you tidy away.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY['https://www.boots.com/lamaze-pile-play-cups-10203340']::text[], 'none'),
    ('cat_two_block_towers', 4, 4, 'visible', true, true, 'Best for plastic stack cups', 'Nuby Stacking Cups', 'Nuby', 'Boots', 'https://www.boots.com/nuby-stacking-cups-10203341', NULL, '£6.00', 'in_stock', 'Suitable from 6 months', 'Bright plastic stacking cups for short tower and tip play when you want an easy wash set for bath and floor stack games.', 'Plastic cups are the washable backup when fabric cups are already in the wash. Keep the session to two short towers so tip play stays kind. Stay nearby while they try Nuby Stacking Cups, then stop on a good note.', 'Plastic cups are the washable backup when fabric cups are already in the wash. Keep the session to two short towers so tip play stays kind. Stay nearby while they try Nuby Stacking Cups, then stop on a good note.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY['https://www.boots.com/nuby-stacking-cups-10203341']::text[], 'none'),
    ('cat_two_block_towers', 5, 5, 'visible', true, true, 'Best for deep block set', 'The Block Set', 'Lovevery', 'Lovevery UK', 'https://www.lovevery.co.uk/products/the-block-set', NULL, '£129.00', 'in_stock', '12 months+', 'A wooden set of seventy solid blocks and shapes in a storage box that becomes a pull car, made for stacking, tipping and rebuilding as hands get steadier.', 'After the first birthday, the fun is placing one block on another and watching the crash. This deep block set keeps enough chunky pieces for short towers now, then grows into sorting later. Put The Block Set where you both sit most evenings so the invite is easy.', 'After the first birthday, the fun is placing one block on another and watching the crash. This deep block set keeps enough chunky pieces for short towers now, then grows into sorting later. Put The Block Set where you both sit most evenings so the invite is easy.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY['https://www.lovevery.co.uk/products/the-block-set']::text[], 'none')
